"use client";

import { useState } from "react";
import { Clock, Shield, AlertTriangle, XCircle, ChevronRight, Globe, User, RefreshCw, Loader2 } from "lucide-react";
import { useRecentScans, useGlobalScans } from "@/lib/hooks/useTrustScan";
import { useWallet } from "@/lib/genlayer/wallet";
import { AddressDisplay } from "./AddressDisplay";
import type { ScanResult, ScanRecord } from "@/lib/contracts/types";

const LABEL_CONFIG = {
  Safe: {
    color: "text-primary",
    bg: "bg-primary/8",
    border: "border-primary/20",
    dot: "bg-primary",
    icon: <Shield className="w-3.5 h-3.5" />,
  },
  Suspicious: {
    color: "text-yellow-400",
    bg: "bg-yellow-400/8",
    border: "border-yellow-400/20",
    dot: "bg-yellow-400",
    icon: <AlertTriangle className="w-3.5 h-3.5" />,
  },
  Dangerous: {
    color: "text-destructive",
    bg: "bg-destructive/8",
    border: "border-destructive/20",
    dot: "bg-destructive",
    icon: <XCircle className="w-3.5 h-3.5" />,
  },
};

function timeAgo(ts: number) {
  const diff = (Date.now() - ts) / 1000;
  if (diff < 60) return "just now";
  if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
  return `${Math.floor(diff / 3600)}h ago`;
}

function shortTarget(t: string) {
  return t.length > 28 ? `${t.slice(0, 14)}...${t.slice(-6)}` : t;
}

export function RecentScans() {
  const { scans, selectScan } = useRecentScans();
  const { globalScans, isLoading: isLoadingGlobal, refresh: refreshGlobal } = useGlobalScans();
  const [view, setView] = useState<"local" | "global">("local");

  const currentScans = view === "local" ? scans : globalScans;
  const isEmpty = currentScans.length === 0;

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-1 p-1 rounded-lg bg-muted/10 border border-border/40 w-fit">
          <button
            onClick={() => setView("local")}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-mono transition-all ${
              view === "local"
                ? "bg-card border border-border text-foreground shadow-sm"
                : "text-muted-foreground hover:text-foreground"
            }`}
          >
            <User className="w-3 h-3" />
            My Scans
            {scans.length > 0 && <span className="opacity-40 text-[10px] ml-0.5">({scans.length})</span>}
          </button>
          <button
            onClick={() => setView("global")}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-mono transition-all ${
              view === "global"
                ? "bg-card border border-border text-foreground shadow-sm"
                : "text-muted-foreground hover:text-foreground"
            }`}
          >
            <Globe className="w-3 h-3" />
            Global Feed
          </button>
        </div>

        {view === "global" && (
          <button
            onClick={refreshGlobal}
            disabled={isLoadingGlobal}
            className="p-2 rounded-md hover:bg-muted/20 text-muted-foreground hover:text-primary transition-all disabled:opacity-50"
          >
            <RefreshCw className={`w-3.5 h-3.5 ${isLoadingGlobal ? "animate-spin" : ""}`} />
          </button>
        )}
      </div>

      <div className="space-y-1">
        {isEmpty ? (
          <div className="ts-card p-10 flex flex-col items-center justify-center gap-2 border-dashed opacity-50 bg-transparent">
            {isLoadingGlobal && view === "global" ? (
              <>
                <Loader2 className="w-6 h-6 animate-spin text-primary/40" />
                <p className="text-sm font-mono text-muted-foreground">Fetching Global Archive...</p>
              </>
            ) : (
              <>
                <Clock className="w-6 h-6 text-muted-foreground/30" />
                <p className="text-sm font-mono text-muted-foreground">
                  {view === "local" ? "No recent scans on this device." : "Global feed is currently empty."}
                </p>
              </>
            )}
          </div>
        ) : (
          currentScans.map((scan, i) => {
            const cfg = LABEL_CONFIG[scan.label as keyof typeof LABEL_CONFIG];
            if (!cfg) return null;

            return (
              <button
                key={i}
                onClick={() => selectScan(scan)}
                className="w-full flex items-center gap-3 px-4 py-3 rounded-lg border border-transparent hover:border-border hover:bg-muted/10 transition-all text-left group"
              >
                {/* Dot with glow */}
                <div className={`w-2 h-2 rounded-full flex-shrink-0 ${cfg.dot}`}
                  style={{ boxShadow: `0 0 8px currentColor` }} />

                {/* Target + metadata */}
                <div className="flex-1 min-w-0 space-y-0.5">
                  <p className="text-xs font-mono text-foreground/80 truncate">
                    {shortTarget(scan.target)}
                  </p>
                  <div className="flex items-center gap-2 text-[10px] font-mono text-muted-foreground uppercase tracking-wider opacity-60">
                    <span>{scan.type ?? "scan"}</span>
                    <span>·</span>
                    <span>{scan.chain && scan.chain !== "n/a" ? scan.chain : "web"}</span>
                    {view === "global" && (
                      <>
                        <span>·</span>
                        <span className="text-primary/60 lowercase">On-Chain Evidence</span>
                      </>
                    )}
                  </div>
                </div>

                {/* Label + Score */}
                <div className="flex items-center gap-3 flex-shrink-0">
                  <div className="flex flex-col items-end">
                    <span className={`text-[10px] font-bold font-mono tracking-wider uppercase ${cfg.color}`}>
                      {scan.label}
                    </span>
                    <span className={`text-sm font-bold font-mono leading-none ${cfg.color}`}>
                      {scan.score}<span className="text-[10px] opacity-40">/100</span>
                    </span>
                  </div>
                  <ChevronRight className="w-4 h-4 text-muted-foreground/20 group-hover:text-primary/50 transition-colors" />
                </div>

                {/* Relative timestamp */}
                <span className="text-[10px] font-mono text-muted-foreground/40 flex-shrink-0 hidden sm:block w-14 text-right">
                  {timeAgo(scan.scannedAt)}
                </span>
              </button>
            )
          })
        )}
      </div>
    </div>
  );
}