"use client";

import { useState, useRef, useEffect } from "react";
import { Loader2, Search, Shield, AlertTriangle, XCircle, Copy, Check, Flag, Share2, ChevronDown, ChevronUp, Layers } from "lucide-react";
import { Logo } from "./Logo";
import { useWallet } from "@/lib/genlayer/wallet";
import { useScan, useRecentScans } from "@/lib/hooks/useTrustScan";
import { Badge } from "./ui/badge";
import { FlagModal } from "@/components/FlagModal";
import TrustScan from "@/lib/contracts/TrustScan";
import type { ScanType, ChainType, FlagResult, ScanResult } from "@/lib/contracts/types";
import * as htmlToImage from "html-to-image";
import { toast } from "sonner";

const SCAN_TYPES: { value: ScanType; label: string; placeholder: string; hint: string; examples: string[] }[] = [
  { value: "wallet", label: "Wallet", placeholder: "0x742d35Cc6634C0532925...", hint: "Ethereum wallet address", examples: ["0x742d35Cc6634C0532925dA2B6F3ab4B6F4e3E1Aa", "0xd8dA6BF26964aF9D7eEd9e03E53415D37aA96045"] },
  { value: "url",    label: "URL",    placeholder: "suspicious-airdrop.com",   hint: "Website or domain to check", examples: ["cysicfinance.com", "uniswap-airdrop.net"] },
  { value: "token",  label: "Token",  placeholder: "0xdAC17F958D2ee523a2206...", hint: "Token contract address", examples: ["0xdAC17F958D2ee523a2206206994597C13D831ec7", "0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48"] },
];

const CHAINS: { value: ChainType; label: string }[] = [
  { value: "eth",  label: "ETH" },
  { value: "bsc",  label: "BSC" },
  { value: "base", label: "Base" },
];

const LABEL_CONFIG = {
  Safe: {
    color: "text-primary", bg: "bg-primary/8", border: "border-primary/25",
    glow: "shadow-[0_0_40px_oklch(0.82_0.18_155/0.20)]", cardGlow: "rgba(0,255,136,0.06)",
    icon: <Shield className="w-5 h-5" />, scoreColor: "text-primary",
    wowLine: "This target looks clean. Safe to interact.", wowColor: "text-primary",
  },
  Suspicious: {
    color: "text-yellow-400", bg: "bg-yellow-400/8", border: "border-yellow-400/25",
    glow: "shadow-[0_0_40px_oklch(0.80_0.18_80/0.20)]", cardGlow: "rgba(255,184,0,0.06)",
    icon: <AlertTriangle className="w-5 h-5" />, scoreColor: "text-yellow-400",
    wowLine: "Proceed with caution. Something doesn't add up.", wowColor: "text-yellow-400",
  },
  Dangerous: {
    color: "text-destructive", bg: "bg-destructive/8", border: "border-destructive/25",
    glow: "shadow-[0_0_40px_oklch(0.65_0.22_25/0.25)]", cardGlow: "rgba(255,61,90,0.08)",
    icon: <XCircle className="w-5 h-5" />, scoreColor: "text-destructive",
    wowLine: "High risk detected. Do not interact with this target.", wowColor: "text-destructive",
  },
};

const SEVERITY_CONFIG = {
  high:   { label: "High",   color: "text-destructive",      bg: "bg-destructive/10", border: "border-destructive/20" },
  medium: { label: "Medium", color: "text-yellow-400",        bg: "bg-yellow-400/10",  border: "border-yellow-400/20" },
  low:    { label: "Low",    color: "text-muted-foreground",  bg: "bg-muted/20",       border: "border-border" },
};

const LIMIT = 10;
const LS_KEY = "ts_scan_data";

function getTodayKey() { return new Date().toISOString().split("T")[0]; }

function getRemaining(): number {
  try {
    const raw = localStorage.getItem(LS_KEY);
    if (!raw) return LIMIT;
    const data = JSON.parse(raw);
    if (data.date !== getTodayKey()) return LIMIT;
    return Math.max(0, LIMIT - (data.count || 0));
  } catch { return LIMIT; }
}

function consumeScan(n = 1): number {
  try {
    const today = getTodayKey();
    const raw = localStorage.getItem(LS_KEY);
    let data = raw ? JSON.parse(raw) : {};
    if (data.date !== today) data = { date: today, count: 0 };
    data.count = (data.count || 0) + n;
    localStorage.setItem(LS_KEY, JSON.stringify(data));
    return Math.max(0, LIMIT - data.count);
  } catch { return LIMIT; }
}

// ─── Mini result card for batch mode ─────────────────────────────────────────
// ─── Mini result card for batch mode ─────────────────────────────────────────
function BatchResultCard({ target, result, flagCount }: { target: string; result: ScanResult | null; flagCount?: number }) {
  if (!result) {
    return (
      <div className="flex items-center gap-3 p-3 rounded-lg border border-border bg-muted/10 opacity-60">
        <div className="w-10 h-10 rounded-full border-2 border-border flex items-center justify-center flex-shrink-0 animate-pulse">
          <span className="text-xs text-muted-foreground font-mono">...</span>
        </div>
        <div className="flex-1 min-w-0">
          <p className="text-xs font-mono text-muted-foreground truncate">{target}</p>
          <p className="text-xs text-muted-foreground mt-0.5">Scanning...</p>
        </div>
      </div>
    );
  }

  const cfg = LABEL_CONFIG[result.label as keyof typeof LABEL_CONFIG];
  if (!cfg) return null;

  return (
    <div className={`flex items-center gap-3 p-3 rounded-lg border ${cfg.border} ${cfg.bg} transition-all hover:scale-[1.01]`}
      style={{ boxShadow: `0 0 12px ${cfg.cardGlow}` }}>
      <div className="relative flex-shrink-0 w-10 h-10">
        <svg viewBox="0 0 80 80" className="w-10 h-10 -rotate-90">
          <circle cx="40" cy="40" r="32" fill="none" stroke="currentColor" strokeWidth="8" className="text-border" />
          <circle cx="40" cy="40" r="32" fill="none" strokeWidth="8" strokeLinecap="round"
            strokeDasharray={`${(result.score / 100) * 201} 201`}
            className={cfg.scoreColor} stroke="currentColor"
            style={{ filter: `drop-shadow(0 0 4px currentColor)` }}
          />
        </svg>
        <div className="absolute inset-0 flex items-center justify-center">
          <span className={`text-xs font-bold ${cfg.scoreColor}`}>{result.score}</span>
        </div>
      </div>

      <div className="flex-1 min-w-0">
        <p className="text-xs font-mono text-foreground/80 truncate">{target}</p>
        <div className="flex items-center gap-2 mt-0.5">
          <div className={`inline-flex items-center gap-1 text-[10px] font-bold uppercase ${cfg.color}`}>
            {cfg.icon && <span className="w-2.5 h-2.5">{cfg.icon}</span>}
            {result.label}
          </div>
          {flagCount && flagCount > 0 ? (
            <div className="flex items-center gap-1 px-1.5 py-0.5 rounded-full bg-destructive/10 border border-destructive/20 text-destructive text-[10px] font-bold">
              <Flag className="w-2.5 h-2.5" />
              {flagCount}
            </div>
          ) : null}
        </div>
      </div>

      {result.signals_found?.[0] && (
        <span className={`text-[10px] px-1.5 py-0.5 rounded border font-mono flex-shrink-0 hidden sm:block ${cfg.color} ${cfg.bg} ${cfg.border} opacity-80`}>
          {result.signals_found[0]}
        </span>
      )}
    </div>
  );
}

export function ScanPanel() {
  const { address, isConnected } = useWallet();
  const { scan, isScanning, phase, result, target: scannedTarget } = useScan();
  // ── FIX: expose addScan so batch results appear in recent scans ──
  const { addScan } = useRecentScans();

  const [mode, setMode] = useState<"single" | "batch">("single");

  const [type, setType]     = useState<ScanType>("wallet");
  const [target, setTarget] = useState("");
  const [chain, setChain]   = useState<ChainType>("eth");
  const [copied, setCopied] = useState(false);
  const [sharing, setSharing] = useState(false);
  const [flagOpen, setFlagOpen]         = useState(false);
  const [showFlags, setShowFlags]       = useState(false);
  const [flags, setFlags]               = useState<FlagResult[]>([]);
  const [flagCount, setFlagCount]       = useState(0);
  const [loadingFlags, setLoadingFlags] = useState(false);

  const [batchInput, setBatchInput]   = useState("");
  const [batchType, setBatchType]     = useState<ScanType>("url");
  const [batchChain, setBatchChain]   = useState<ChainType>("eth");
  const [isBatchScanning, setIsBatchScanning] = useState(false);
  const [batchPhase, setBatchPhase]   = useState("");
  const [batchResults, setBatchResults] = useState<Record<string, ScanResult | null>>({});
  const [batchFlagCounts, setBatchFlagCounts] = useState<Record<string, number>>({});
  const [batchTargets, setBatchTargets] = useState<string[]>([]);

  const [remaining, setRemaining] = useState(() => {
    if (typeof window === "undefined") return LIMIT;
    return getRemaining();
  });

  const shareRef = useRef<HTMLDivElement>(null);
  const cfg = result ? LABEL_CONFIG[result.label as keyof typeof LABEL_CONFIG] : null;
  const currentType = SCAN_TYPES.find(t => t.value === type)!;

  useEffect(() => {
    setRemaining(getRemaining());
    const storageListener = (e: StorageEvent) => {
      if (e.key === LS_KEY) setRemaining(getRemaining());
    };
    window.addEventListener("storage", storageListener);
    return () => window.removeEventListener("storage", storageListener);
  }, []);

  useEffect(() => {
    if (!scannedTarget) return;
    const fetchFlags = async () => {
      setLoadingFlags(true);
      try {
        const contract = new TrustScan();
        const [flagData, count] = await Promise.all([
          contract.getFlags(scannedTarget),
          contract.getFlagCount(scannedTarget),
        ]);
        setFlags(flagData);
        setFlagCount(count);
      } catch (e) {
        console.error("Failed to load flags:", e);
      } finally {
        setLoadingFlags(false);
      }
    };
    fetchFlags();
  }, [scannedTarget]);

  const handleScan = () => {
    if (!target.trim() || !isConnected || !address || remaining <= 0) return;
    setFlags([]);
    setFlagCount(0);
    setShowFlags(false);
    const newRemaining = consumeScan(1);
    setRemaining(newRemaining);
    scan({ target: target.trim(), type, chain, address });
  };

  const handleBatchScan = async () => {
    if (!isConnected || !address) return;

    const targets = batchInput
      .split("\n")
      .map(t => t.trim())
      .filter(Boolean)
      .slice(0, 10);

    if (targets.length === 0) return;
    if (targets.length > remaining) {
      toast.error(`Not enough scans remaining. You have ${remaining} left today.`);
      return;
    }

    setIsBatchScanning(true);
    setBatchResults({});
    setBatchTargets(targets);
    setBatchPhase("Submitting batch to GenLayer...");

    try {
      const scanContract = new TrustScan(address);

      const normalized = targets.map(t =>
        batchType !== "url" ? t.toLowerCase() : t
      );

      setBatchPhase(`Scanning ${targets.length} targets...`);
      await scanContract.scanMultiple(normalized, batchType, batchChain);

      const newRemaining = consumeScan(targets.length);
      setRemaining(newRemaining);

      setBatchPhase("Fetching results...");
      const readContract = new TrustScan();
      let results: Record<string, ScanResult | null> = {};

      for (let i = 0; i < 10; i++) {
        results = await readContract.getMultipleScores(normalized);
        const allReady = normalized.every(t => results[t] !== null);
        if (allReady) break;
        await new Promise(r => setTimeout(r, 5000));
      }

      setBatchResults(results);

      // ── NEW: Fetch flag counts for all targets in the batch ──
      setBatchPhase("Checking community reports...");
      const flagCounts: Record<string, number> = {};
      await Promise.all(
        normalized.map(async (t) => {
          const count = await readContract.getFlagCount(t);
          flagCounts[t] = count;
        })
      );
      setBatchFlagCounts(flagCounts);

      // ── FIX: add each batch result to recent scans ──
      Object.entries(results).forEach(([t, r]) => {
        if (r) addScan({ ...r, target: t, scannedAt: Date.now() });
      });

      toast.success(`Batch scan complete. ${targets.length} targets analyzed.`);

    } catch (e: any) {
      console.error("Batch scan error:", e);
      toast.error("Batch scan failed", { description: e.message || "Please try again." });
    } finally {
      setIsBatchScanning(false);
      setBatchPhase("");
    }
  };

  const batchShareRef = useRef<HTMLDivElement>(null);
  const [batchSharing, setBatchSharing] = useState(false);

  const handleBatchShare = async () => {
    if (!batchShareRef.current) return;
    setBatchSharing(true);
    try {
      const dataUrl = await htmlToImage.toPng(batchShareRef.current, {
        quality: 1, pixelRatio: 2, backgroundColor: "#080b0f",
      });
      const link = document.createElement("a");
      link.download = `trustscan-batch.png`;
      link.href = dataUrl;
      link.click();
      toast.success("Batch report exported!");
    } catch (e) {
      console.error("Batch share failed:", e);
      toast.error("Export failed");
    } finally {
      setBatchSharing(false);
    }
  };

  const handleCopy = () => {
    if (!result || !scannedTarget) return;
    const text = [
      `TrustScan Result`,
      `Target: ${scannedTarget}`,
      `Score:  ${result.score}/100`,
      `Label:  ${result.label}`,
      ``,
      result.reason,
      ``,
      `Signals: ${(result.signals_found ?? []).join(", ")}`,
      ``,
      `Powered by TrustScan on GenLayer`,
    ].join("\n");
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleShare = async () => {
    if (!shareRef.current) return;
    setSharing(true);
    try {
      const dataUrl = await htmlToImage.toPng(shareRef.current, {
        quality: 1, pixelRatio: 2, backgroundColor: "#080b0f",
      });
      const link = document.createElement("a");
      link.download = `trustscan-${(scannedTarget ?? "result").slice(0, 12)}.png`;
      link.href = dataUrl;
      link.click();
    } catch (e) {
      console.error("Share failed:", e);
    } finally {
      setSharing(false);
    }
  };

  const handleFlagSuccess = async () => {
    setFlagOpen(false);
    if (!scannedTarget) return;
    try {
      const contract = new TrustScan();
      const [flagData, count] = await Promise.all([
        contract.getFlags(scannedTarget),
        contract.getFlagCount(scannedTarget),
      ]);
      setFlags(flagData);
      setFlagCount(count);
      setShowFlags(true);
    } catch (e) {
      console.error("Failed to refresh flags:", e);
    }
  };

  const batchTargetList = batchInput.split("\n").map(t => t.trim()).filter(Boolean).slice(0, 10);
  const hasBatchResults = Object.keys(batchResults).length > 0;

  return (
    <div className="space-y-4">
      {/* Mode toggle */}
      <div className="flex items-center gap-1 p-1 rounded-lg bg-muted/20 border border-border w-fit">
        <button
          onClick={() => setMode("single")}
          className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-mono transition-all ${
            mode === "single"
              ? "bg-card border border-border text-foreground"
              : "text-muted-foreground hover:text-foreground"
          }`}
        >
          <Search className="w-3 h-3" />
          Single
        </button>
        <button
          onClick={() => setMode("batch")}
          className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-mono transition-all ${
            mode === "batch"
              ? "bg-card border border-border text-foreground"
              : "text-muted-foreground hover:text-foreground"
          }`}
        >
          <Layers className="w-3 h-3" />
          Batch
          <span className="text-xs opacity-50">up to 10</span>
        </button>
      </div>

      {/* ─── SINGLE SCAN MODE ─────────────────────────── */}
      {mode === "single" && (
        <div className="ts-card p-5">
          <div className="flex items-center gap-1 mb-4 flex-wrap">
            {SCAN_TYPES.map(t => (
              <button
                key={t.value}
                onClick={() => setType(t.value)}
                disabled={isScanning}
                className={`px-3 py-1.5 rounded-md text-xs font-mono uppercase tracking-widest transition-all ${
                  type === t.value
                    ? "bg-primary/15 border border-primary/40 text-primary"
                    : "text-muted-foreground hover:text-foreground hover:bg-muted/30 border border-transparent"
                }`}
              >
                {t.label}
              </button>
            ))}
            {type === "token" && (
              <div className="flex items-center gap-1 ml-auto">
                {CHAINS.map(c => (
                  <button
                    key={c.value}
                    onClick={() => setChain(c.value)}
                    disabled={isScanning}
                    className={`px-2.5 py-1.5 rounded-md text-xs font-mono transition-all ${
                      chain === c.value
                        ? "bg-primary/15 border border-primary/40 text-primary"
                        : "text-muted-foreground hover:text-foreground border border-transparent hover:border-border"
                    }`}
                  >
                    {c.label}
                  </button>
                ))}
              </div>
            )}
          </div>

          <div className="flex gap-2">
            <input
              type="text"
              value={target}
              onChange={e => setTarget(e.target.value)}
              onKeyDown={e => e.key === "Enter" && !isScanning && handleScan()}
              placeholder={currentType.placeholder}
              disabled={isScanning}
              spellCheck={false}
              autoComplete="off"
              className="ts-input flex-1 px-4 py-3 text-sm font-mono min-w-0"
            />
            <button
              onClick={handleScan}
              disabled={isScanning || !target.trim() || !isConnected || remaining <= 0}
              className="btn-primary w-11 h-11 flex items-center justify-center flex-shrink-0 disabled:opacity-40 disabled:cursor-not-allowed rounded-lg"
            >
              {isScanning ? <Loader2 className="w-4 h-4 animate-spin" /> : <Search className="w-4 h-4" />}
            </button>
          </div>

          <div className="flex items-center gap-2 mt-3 flex-wrap">
            <span className="text-xs text-muted-foreground font-mono">Try:</span>
            {currentType.examples.map((ex, i) => (
              <button
                key={i}
                onClick={() => setTarget(ex)}
                disabled={isScanning}
                className="text-xs font-mono text-muted-foreground hover:text-primary transition-colors truncate max-w-[140px]"
              >
                {ex.length > 18 ? `${ex.slice(0, 8)}...${ex.slice(-6)}` : ex}
              </button>
            ))}
          </div>

          <div className="flex items-center justify-between mt-2">
            <span className="text-xs text-muted-foreground font-mono">
              {isScanning && phase
                ? <span className="text-primary animate-pulse">{phase}</span>
                : currentType.hint
              }
            </span>
            <span className={`text-xs font-mono ${remaining <= 3 ? "text-destructive" : "text-muted-foreground"}`}>
              {remaining}/{LIMIT} scans today
            </span>
          </div>
        </div>
      )}

      {/* ─── BATCH SCAN MODE ──────────────────────────── */}
      {mode === "batch" && (
        <div className="ts-card p-5">
          <div className="flex items-center gap-1 mb-4 flex-wrap">
            {SCAN_TYPES.map(t => (
              <button
                key={t.value}
                onClick={() => setBatchType(t.value)}
                disabled={isBatchScanning}
                className={`px-3 py-1.5 rounded-md text-xs font-mono uppercase tracking-widest transition-all ${
                  batchType === t.value
                    ? "bg-primary/15 border border-primary/40 text-primary"
                    : "text-muted-foreground hover:text-foreground hover:bg-muted/30 border border-transparent"
                }`}
              >
                {t.label}
              </button>
            ))}
            {batchType === "token" && (
              <div className="flex items-center gap-1 ml-auto">
                {CHAINS.map(c => (
                  <button
                    key={c.value}
                    onClick={() => setBatchChain(c.value)}
                    disabled={isBatchScanning}
                    className={`px-2.5 py-1.5 rounded-md text-xs font-mono transition-all ${
                      batchChain === c.value
                        ? "bg-primary/15 border border-primary/40 text-primary"
                        : "text-muted-foreground hover:text-foreground border border-transparent hover:border-border"
                    }`}
                  >
                    {c.label}
                  </button>
                ))}
              </div>
            )}
          </div>

          <textarea
            value={batchInput}
            onChange={e => setBatchInput(e.target.value)}
            placeholder={`One target per line (max 10)\n\ncysicfinance.com\nuniswap-airdrop.net\nsuspicious-claim.io`}
            disabled={isBatchScanning}
            rows={5}
            spellCheck={false}
            className="ts-input w-full px-4 py-3 text-sm font-mono resize-none leading-relaxed"
          />

          <div className="flex items-center justify-between mt-3">
            <span className="text-xs text-muted-foreground font-mono">
              {isBatchScanning && batchPhase
                ? <span className="text-primary animate-pulse">{batchPhase}</span>
                : batchTargetList.length > 0
                  ? `${batchTargetList.length} target${batchTargetList.length !== 1 ? "s" : ""} queued`
                  : "Paste targets above, one per line"
              }
            </span>
            <div className="flex items-center gap-3">
              <span className={`text-xs font-mono ${remaining <= 3 ? "text-destructive" : "text-muted-foreground"}`}>
                {remaining}/{LIMIT} scans today
              </span>
              <button
                onClick={handleBatchScan}
                disabled={isBatchScanning || batchTargetList.length === 0 || !isConnected || remaining <= 0}
                className="btn-primary px-4 h-9 flex items-center gap-2 text-xs font-mono disabled:opacity-40 disabled:cursor-not-allowed rounded-lg"
              >
                {isBatchScanning
                  ? <><Loader2 className="w-3.5 h-3.5 animate-spin" /> Scanning...</>
                  : <><Layers className="w-3.5 h-3.5" /> Scan All</>
                }
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ─── BATCH SCANNING SKELETON ──────────────────── */}
      {isBatchScanning && (
        <div className="ts-card p-8 flex flex-col items-center gap-4">
          <div className="relative w-14 h-14 flex items-center justify-center">
            <div className="absolute inset-0 rounded-full border-2 border-primary/20 border-t-primary animate-spin" />
            <Layers className="w-5 h-5 text-primary/60" />
          </div>
          <div className="text-center space-y-1">
            <p className="text-sm font-semibold">Batch scanning {batchTargetList.length} targets...</p>
            <p className="text-xs text-muted-foreground font-mono max-w-xs">
              GenLayer AI validators are cross-referencing all targets simultaneously
            </p>
          </div>
        </div>
      )}

      {/* ─── BATCH RESULTS ────────────────────────────── */}
      {!isBatchScanning && hasBatchResults && (
        <div className="ts-card overflow-hidden">
          <div ref={batchShareRef} className="p-4 bg-[#080b0f]">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-2">
                <Logo className="w-5 h-5" />
                <span className="text-sm font-bold tracking-tight">TrustScan Batch Report</span>
              </div>
              <span className="text-[10px] font-mono text-muted-foreground uppercase opacity-60">
                {new Date().toLocaleString()}
              </span>
            </div>
            <div className="space-y-2">
              {batchTargets.map(t => (
                <BatchResultCard
                  key={t}
                  target={t}
                  result={batchResults[t] ?? null}
                  flagCount={batchFlagCounts[t] ?? 0}
                />
              ))}
            </div>
            <div className="mt-4 pt-3 border-t border-border flex items-center justify-between">
              <span className="text-[10px] text-muted-foreground font-mono">GenLayer AI · Etherscan · GoPlus · Chainabuse</span>
              <span className="text-[10px] text-muted-foreground font-mono">Verification: On-Chain</span>
            </div>
          </div>

          <div className="flex border-t border-border">
            <button
              onClick={handleBatchShare}
              disabled={batchSharing}
              className="w-full flex items-center justify-center gap-2 py-3 text-xs font-mono text-muted-foreground hover:text-primary hover:bg-primary/5 transition-colors"
            >
              {batchSharing ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Share2 className="w-3.5 h-3.5" />}
              Export Batch Report
            </button>
          </div>
        </div>
      )}

      {/* ─── SINGLE SCAN SKELETON ─────────────────────── */}
      {mode === "single" && isScanning && (
        <div className="ts-card p-8 flex flex-col items-center gap-4">
          <div className="relative w-14 h-14 flex items-center justify-center">
            <div className="absolute inset-0 rounded-full border-2 border-primary/20 border-t-primary animate-spin" />
            <Shield className="w-5 h-5 text-primary/60" />
          </div>
          <div className="text-center space-y-1">
            <p className="text-sm font-semibold">Analyzing target...</p>
            <p className="text-xs text-muted-foreground font-mono max-w-xs">
              GenLayer AI validators are cross-referencing Etherscan, GoPlus, and Chainabuse
            </p>
          </div>
        </div>
      )}

      {/* ─── SINGLE RESULT CARD ───────────────────────── */}
      {mode === "single" && !isScanning && result && scannedTarget && cfg && (
        <div
          className={`ts-card overflow-hidden ${cfg.glow}`}
          id="scan-result"
          style={{ background: `linear-gradient(135deg, ${cfg.cardGlow} 0%, transparent 60%)` }}
        >
          <div ref={shareRef} className="p-6" style={{ background: `linear-gradient(135deg, ${cfg.cardGlow} 0%, #080b0f 60%)` }}>
            <div className="flex items-center gap-5 mb-5">
              <div className="relative flex-shrink-0 w-28 h-28">
                <svg viewBox="0 0 80 80" className="w-28 h-28 -rotate-90">
                  <circle cx="40" cy="40" r="32" fill="none" stroke="currentColor" strokeWidth="6" className="text-border" />
                  <circle cx="40" cy="40" r="32" fill="none" strokeWidth="6" strokeLinecap="round"
                    strokeDasharray={`${(result.score / 100) * 201} 201`}
                    className={cfg.scoreColor} stroke="currentColor"
                    style={{ filter: `drop-shadow(0 0 10px currentColor)`, transition: "stroke-dasharray 1s ease" }}
                  />
                </svg>
                <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <span className={`text-3xl font-bold leading-none ${cfg.scoreColor}`}>{result.score}</span>
                  <span className="text-xs text-muted-foreground font-mono">/100</span>
                </div>
              </div>
              <div className="flex-1 min-w-0 space-y-2">
                <div className={`inline-flex items-center gap-2 px-4 py-2.5 rounded-lg border text-xl font-bold uppercase tracking-wider ${cfg.color} ${cfg.bg} ${cfg.border}`}
                  style={{ boxShadow: `0 0 20px ${cfg.cardGlow}` }}>
                  {cfg.icon}{result.label}
                </div>
                <p className="text-xs text-muted-foreground font-mono truncate">{scannedTarget}</p>
                <div className="flex gap-1.5">
                  {result.type && <Badge variant="outline" className="text-xs font-mono px-2">{result.type}</Badge>}
                  {result.chain && result.chain !== "n/a" && <Badge variant="outline" className="text-xs font-mono px-2">{result.chain}</Badge>}
                </div>
              </div>
            </div>

            <div className="p-4 rounded-lg bg-muted/15 border border-border mb-4">
              <p className="text-sm leading-relaxed">{result.reason}</p>
            </div>

            {result.signals_found && result.signals_found.length > 0 && (
              <div className="flex flex-wrap gap-1.5 mb-4">
                {result.signals_found.slice(0, 3).map((s: string, i: number) => (
                  <span key={i} className={`text-xs px-2.5 py-1 rounded-md border font-mono ${cfg.color} ${cfg.bg} ${cfg.border}`}>{s}</span>
                ))}
                {result.signals_found.length > 3 && (
                  <span className="text-xs px-2.5 py-1 rounded-md border font-mono text-muted-foreground bg-muted/20 border-border">
                    +{result.signals_found.length - 3} more
                  </span>
                )}
              </div>
            )}

            <div className={`flex items-center gap-2 py-2.5 px-3 rounded-lg ${cfg.bg} border ${cfg.border} mb-3`}>
              <span className="text-sm font-semibold font-mono">{cfg.wowLine}</span>
            </div>

            <div className="flex items-center justify-between pt-3 border-t border-border">
              <span className="text-xs text-muted-foreground font-mono">TrustScan · GenLayer AI</span>
              <span className="text-xs text-muted-foreground font-mono">Etherscan · GoPlus · Chainabuse</span>
            </div>
          </div>

          <div className="flex border-t border-border divide-x divide-border">
            <button onClick={handleShare} disabled={sharing}
              className="flex-1 flex items-center justify-center gap-2 py-3 text-xs font-mono text-muted-foreground hover:text-primary hover:bg-primary/5 transition-colors">
              {sharing ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Share2 className="w-3.5 h-3.5" />}
              Share Proof
            </button>
            <button onClick={handleCopy}
              className="flex-1 flex items-center justify-center gap-2 py-3 text-xs font-mono text-muted-foreground hover:text-foreground hover:bg-muted/20 transition-colors">
              {copied ? <><Check className="w-3.5 h-3.5 text-primary" /> Copied</> : <><Copy className="w-3.5 h-3.5" /> Copy Result</>}
            </button>
            <button onClick={() => { if (!isConnected) return; setFlagOpen(true); }}
              className="flex-1 flex items-center justify-center gap-2 py-3 text-xs font-mono text-muted-foreground hover:text-destructive hover:bg-destructive/5 transition-colors">
              <Flag className="w-3.5 h-3.5" />
              Flag
              {flagCount > 0 && (
                <span className="bg-destructive text-white text-xs font-bold rounded-full w-4 h-4 flex items-center justify-center">
                  {flagCount}
                </span>
              )}
            </button>
          </div>

          {flagCount > 0 && (
            <div className="border-t border-border">
              <button onClick={() => setShowFlags(!showFlags)}
                className="w-full flex items-center justify-between px-5 py-3 text-xs font-mono text-muted-foreground hover:text-foreground hover:bg-muted/10 transition-colors">
                <span>{flagCount} community report{flagCount !== 1 ? "s" : ""}</span>
                {showFlags ? <ChevronUp className="w-3.5 h-3.5" /> : <ChevronDown className="w-3.5 h-3.5" />}
              </button>
              {showFlags && (
                <div className="px-5 pb-4 space-y-3">
                  {loadingFlags ? (
                    <div className="flex items-center gap-2 py-2 text-xs text-muted-foreground font-mono">
                      <Loader2 className="w-3.5 h-3.5 animate-spin" /> Loading reports...
                    </div>
                  ) : flags.length === 0 ? (
                    <p className="text-xs text-muted-foreground font-mono py-2">No reports found.</p>
                  ) : (
                    flags.map((f, i) => {
                      const sev = SEVERITY_CONFIG[f.severity as keyof typeof SEVERITY_CONFIG] ?? SEVERITY_CONFIG.low;
                      return (
                        <div key={i} className={`p-3 rounded-lg border ${sev.bg} ${sev.border}`}>
                          <div className="flex items-center gap-2 mb-1.5">
                            <span className={`text-xs font-bold font-mono px-2 py-0.5 rounded ${sev.color} ${sev.bg} border ${sev.border}`}>{sev.label}</span>
                            {f.credible && <span className="text-xs text-primary font-mono">✓ verified</span>}
                            <span className="text-xs text-muted-foreground font-mono ml-auto">
                              {f.reporter ? `${f.reporter.slice(0, 6)}...${f.reporter.slice(-4)}` : "anon"}
                            </span>
                          </div>
                          <p className="text-xs text-foreground/80 leading-relaxed">{f.summary}</p>
                        </div>
                      );
                    })
                  )}
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {flagOpen && scannedTarget && (
        <FlagModal
          target={scannedTarget}
          onClose={() => setFlagOpen(false)}
          onSuccess={handleFlagSuccess}
        />
      )}
    </div>
  );
}